#include "controller.h"

static void controller_set_safe_off(controller_t *controller)
{
    controller->pump_on = false;
    controller->state = CONTROLLER_STATE_SAFE_OFF;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_off(controller);
    controller->has_valid_sensor = false;
    controller->last_level = 0;
    controller->last_valid_sensor_ms = 0U;
}

static void controller_turn_pump_on(controller_t *controller)
{
    controller->pump_on = true;
    controller->state = CONTROLLER_STATE_PUMPING;
}

static void controller_turn_pump_off(controller_t *controller)
{
    controller->pump_on = false;
    if (controller->state == CONTROLLER_STATE_PUMPING) {
        controller->state = CONTROLLER_STATE_SAFE_OFF;
    } else {
        controller->state = CONTROLLER_STATE_HOLDING;
    }
}

static bool controller_should_pump(int level)
{
    return level < CONTROLLER_LEVEL_LOW_THRESHOLD;
}

static bool controller_should_stop(int level)
{
    return level > CONTROLLER_LEVEL_HIGH_THRESHOLD;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .pump_on = false,
        .state = CONTROLLER_STATE_SAFE_OFF,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF),
        .changed = false,
        .timed_out = false,
    };
    bool previous_pump_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_pump_on = controller->pump_on;
    previous_state = controller->state;

    /* Handle timeout: no valid sensor for > 1000ms */
    bool timed_out = false;
    if (controller->has_valid_sensor) {
        uint32_t elapsed_ms = input.now_ms - controller->last_valid_sensor_ms;
        if (elapsed_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
            timed_out = true;
            controller_set_safe_off(controller);
        }
    }

    /* Handle timeout case */
    if (timed_out) {
        output.timed_out = true;
        output.pump_on = false;
        output.state = CONTROLLER_STATE_SAFE_OFF;
        output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF);
        return output;
    }

    /* Handle invalid input cases: malformed or sensor timeout */
    switch (input.kind) {
    case CONTROLLER_INPUT_LEVEL:
        {
            int level = input.level;

            if (!controller_should_pump(level)) {
                if (!controller_should_stop(level)) {
                    /* Holding zone: 30 <= LEVEL <= 80 */
                    controller->state = CONTROLLER_STATE_HOLDING;
                    /* Keep previous pump state when holding */
                } else {
                    /* LEVEL > 80: turn pump off */
                    controller_turn_pump_off(controller);
                }
            } else {
                /* LEVEL < 30: turn pump on */
                controller_turn_pump_on(controller);
            }

            controller->has_valid_sensor = true;
            controller->last_level = level;
            controller->last_valid_sensor_ms = input.now_ms;
        }
        break;
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
        {
            /* Sensor timeout event - fail safe to OFF */
            controller_set_safe_off(controller);
        }
        break;
    case CONTROLLER_INPUT_INVALID_LEVEL:
        {
            /* Invalid level value - fail safe to OFF */
            controller_set_safe_off(controller);
        }
        break;
    case CONTROLLER_INPUT_NONE:
        {
            /* No input - maintain current state unless timed out (handled above) */
            /* Keep existing pump_on and state values */
        }
        break;
    default:
        {
            /* Unknown input kind - fail safe to OFF */
            controller_set_safe_off(controller);
        }
        break;
    }

    output.pump_on = controller->pump_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_pump_on != controller->pump_on) || (previous_state != controller->state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_PUMPING:
        return "STATE PUMPING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_OFF:
    default:
        return "STATE SAFE_OFF";
    }
}

